import{_ as r,I as a,f as n,i as s}from"./chunks/framework.Cm2kD3v9.js";const h=JSON.parse('{"title":"Features","description":"","frontmatter":{},"headers":[],"relativePath":"introduction/features.md","filePath":"introduction/features.md"}'),o={name:"introduction/features.md"};function i(t,e,c,d,l,u){return a(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to “Features”">​</a></h1><p>Turna combines four operational building blocks in one binary.</p><h2 id="configuration-loader" tabindex="-1">Configuration Loader <a class="header-anchor" href="#configuration-loader" aria-label="Permalink to “Configuration Loader”">​</a></h2><p>Turna loads its own configuration from files, environment variables, Consul, and Vault. The <code>loads</code> section can also fetch extra data and expose it to templates, generated files, server configuration, or service environment variables.</p><h2 id="preprocess" tabindex="-1">Preprocess <a class="header-anchor" href="#preprocess" aria-label="Permalink to “Preprocess”">​</a></h2><p>Preprocess modules run after <code>loads</code> and before the server or services start. The current module is <code>replace</code>, which can rewrite files using static strings, regular expressions, templates, or values loaded into memory.</p><h2 id="server" tabindex="-1">Server <a class="header-anchor" href="#server" aria-label="Permalink to “Server”">​</a></h2><p>The server layer provides named entrypoints and routers. HTTP routers run ordered middleware chains; TCP routers run connection middleware chains.</p><p>Common HTTP use cases include reverse proxying, static file serving, CORS, headers, compression, request rewrites, OAuth/session flows, IAM checks, and access logging.</p><p>Common TCP use cases include TCP redirects, Unix socket exposure, SOCKS5 proxying, and IP allow-listing.</p><h2 id="service-runner" tabindex="-1">Service Runner <a class="header-anchor" href="#service-runner" aria-label="Permalink to “Service Runner”">​</a></h2><p>The service runner starts local commands with templated environment variables. Services can be ordered, run in parallel by order group, depend on other services, ignore allowed failures, inherit the process environment, and filter command output.</p>',12)])])}const m=r(o,[["render",i]]);export{h as __pageData,m as default};
